mapper.select:
select s.id, s.scada_guid, s.serial_number, d.device_name, d.status, p.device_type
from scada_device_bind s left join iot_device d on s.serial_number = d.serial_number
left join iot_product p on d.product_id = p.product_id
where s.scada_guid = #{scadaDeviceBindVO.scadaGuid}
  and d.del_flag = '0'

  and s.serial_number = #{scadaDeviceBindVO.serialNumber}
